import React, { useState } from 'react';
import { LandRecord, PlotDetails } from '../../types';
import { mockLandRecords } from '../../data/mockData';
import LandForm from './LandForm';
import LandList from './LandList';
import PlotDetailsModal from './PlotDetailsModal';

const AdminDashboard: React.FC = () => {
  const [landRecords, setLandRecords] = useState<LandRecord[]>(mockLandRecords);
  const [showForm, setShowForm] = useState(false);
  const [selectedLand, setSelectedLand] = useState<LandRecord | null>(null);
  const [selectedPlot, setSelectedPlot] = useState<PlotDetails | null>(null);
  const [showPlotModal, setShowPlotModal] = useState(false);

  const handleAddPlot = (plotData: Omit<PlotDetails, 'id'>) => {
    if (!selectedLand) return;

    const newPlot: PlotDetails = {
      ...plotData,
      id: `plot-${Date.now()}`
    };

    const updatedLandRecords = landRecords.map(land =>
      land.id === selectedLand.id
        ? {
            ...land,
            plots: [...land.plots, newPlot],
            updatedAt: new Date().toISOString()
          }
        : land
    );

    setLandRecords(updatedLandRecords);
    setShowForm(false);
  };

  const handleLandSelect = (land: LandRecord) => {
    setSelectedLand(land);
  };

  const handlePlotSelect = (plot: PlotDetails) => {
    setSelectedPlot(plot);
    setShowPlotModal(true);
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h1 className="text-3xl font-bold text-gray-900">Admin Dashboard</h1>
        {selectedLand && (
          <button
            onClick={() => setShowForm(true)}
            className="px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            Add New Plot to {selectedLand.landNumber}
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Land Records List */}
        <div className="lg:col-span-1">
          <div className="bg-white rounded-lg shadow">
            <div className="px-6 py-4 border-b">
              <h2 className="text-lg font-semibold text-gray-900">Land Records</h2>
            </div>
            <div className="p-6">
              <div className="space-y-2">
                {landRecords.map(land => (
                  <div
                    key={land.id}
                    onClick={() => handleLandSelect(land)}
                    className={`p-3 rounded-lg cursor-pointer transition-colors ${
                      selectedLand?.id === land.id
                        ? 'bg-blue-50 border-2 border-blue-500'
                        : 'bg-gray-50 border-2 border-transparent hover:bg-gray-100'
                    }`}
                  >
                    <div className="font-medium text-gray-900">{land.landNumber}</div>
                    <div className="text-sm text-gray-500">
                      {land.plots.length} plots • {land.raqba.value} {land.raqba.unit}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* Selected Land Details */}
        <div className="lg:col-span-2">
          {selectedLand ? (
            <div className="space-y-6">
              <div className="bg-white rounded-lg shadow">
                <div className="px-6 py-4 border-b">
                  <h2 className="text-lg font-semibold text-gray-900">
                    {selectedLand.landNumber} Details
                  </h2>
                </div>
                <div className="p-6">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <span className="text-sm font-medium text-gray-500">Land Number:</span>
                      <p className="text-lg font-semibold text-gray-900">{selectedLand.landNumber}</p>
                    </div>
                    <div>
                      <span className="text-sm font-medium text-gray-500">Total Area:</span>
                      <p className="text-lg font-semibold text-gray-900">
                        {selectedLand.raqba.value} {selectedLand.raqba.unit}
                      </p>
                    </div>
                    <div>
                      <span className="text-sm font-medium text-gray-500">Total Plots:</span>
                      <p className="text-lg font-semibold text-gray-900">{selectedLand.plots.length}</p>
                    </div>
                    <div>
                      <span className="text-sm font-medium text-gray-500">Last Updated:</span>
                      <p className="text-lg font-semibold text-gray-900">
                        {new Date(selectedLand.updatedAt).toLocaleDateString()}
                      </p>
                    </div>
                  </div>
                </div>
              </div>

              <LandList
                plots={selectedLand.plots}
                onPlotSelect={handlePlotSelect}
              />
            </div>
          ) : (
            <div className="bg-white rounded-lg shadow p-12 text-center">
              <div className="text-gray-500">
                <svg className="mx-auto h-12 w-12 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                </svg>
                <h3 className="mt-2 text-sm font-medium text-gray-900">No land selected</h3>
                <p className="mt-1 text-sm text-gray-500">
                  Select a land record from the list to view details and manage plots.
                </p>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Add Plot Form Modal */}
      {showForm && (
        <div className="fixed inset-0 bg-gray-600 bg-opacity-50 overflow-y-auto h-full w-full z-50">
          <div className="relative top-20 mx-auto p-5 border w-11/12 max-w-6xl shadow-lg rounded-md bg-white">
            <div className="mt-3">
              <LandForm
                onSubmit={handleAddPlot}
                onCancel={() => setShowForm(false)}
              />
            </div>
          </div>
        </div>
      )}

      {/* Plot Details Modal */}
      {showPlotModal && selectedPlot && (
        <PlotDetailsModal
          plot={selectedPlot}
          onClose={() => setShowPlotModal(false)}
        />
      )}
    </div>
  );
};

export default AdminDashboard;
